function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return null;
}

function asArray(value) {
  if (!value) return [];
  return Array.isArray(value) ? value : [value];
}

function isBlank(v) {
  if (v === undefined || v === null) return true;
  const s = String(v).trim();
  return s === '' || s.toLowerCase() === 'null' || s.toLowerCase() === 'undefined';
}

function isUuid(v) {
  if (isBlank(v)) return false;
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(v).trim());
}

function uuidOrNull(v) {
  return isUuid(v) ? String(v).trim() : null;
}

function toBool(value) {
  return value === true || value === 'true';
}

function canonicalOutputType(value, rawText, briefSummary) {
  const v = String(value || '').trim().toLowerCase();
  const text = `${rawText || ''} ${briefSummary || ''}`.toLowerCase();

  const allowed = new Set([
    'image_prompt',
    'video_prompt',
    'frame_by_frame_prompt',
    'product_ad_prompt',
    'social_media_prompt',
    'key_visual_prompt',
    'retouching_prompt',
    'reference_analysis',
    'campaign_concept',
    'prompt_repair',
    'full_creative_direction'
  ]);

  const map = {
    image: 'image_prompt',
    image_prompt: 'image_prompt',
    visual_prompt: 'image_prompt',

    video: 'video_prompt',
    video_prompt: 'video_prompt',

    frame_by_frame: 'frame_by_frame_prompt',
    frame_by_frame_prompt: 'frame_by_frame_prompt',

    product_ad: 'product_ad_prompt',
    product_ad_prompt: 'product_ad_prompt',
    product_advertising_prompt: 'product_ad_prompt',
    advertising_prompt: 'product_ad_prompt',
    ad_prompt: 'product_ad_prompt',
    car_ad_prompt: 'product_ad_prompt',
    automotive_ad_prompt: 'product_ad_prompt',

    social: 'social_media_prompt',
    social_media_prompt: 'social_media_prompt',
    social_media_visual_prompt: 'social_media_prompt',

    key_visual: 'key_visual_prompt',
    key_visual_prompt: 'key_visual_prompt',

    retouching: 'retouching_prompt',
    retouching_prompt: 'retouching_prompt',
    retouching_direction: 'retouching_prompt',
    retouch_direction: 'retouching_prompt',

    reference_analysis: 'reference_analysis',

    campaign_prompt: 'campaign_concept',
    campaign_request: 'campaign_concept',
    campaign_concept: 'campaign_concept',

    prompt_revision: 'prompt_repair',
    prompt_repair: 'prompt_repair',

    full_creative_direction: 'full_creative_direction',
    creative_direction: 'full_creative_direction',
    art_direction: 'full_creative_direction'
  };

  if (map[v]) return map[v];

  if (text.includes('frame by frame') || text.includes('shot by shot') || text.includes('storyboard')) return 'frame_by_frame_prompt';
  if (text.includes('video') || text.includes('motion') || text.includes('فيديو')) return 'video_prompt';
  if (text.includes('campaign') || text.includes('حملة') || text.includes('كامبين')) return 'campaign_concept';
  if (text.includes('repair') || text.includes('revise') || text.includes('revision') || text.includes('fix prompt')) return 'prompt_repair';
  if (text.includes('retouch') || text.includes('ريتاتش')) return 'retouching_prompt';
  if (text.includes('key visual') || text.includes('kv') || text.includes('كي فيجوال') || text.includes('فيجوال رئيسي')) return 'key_visual_prompt';
  if (text.includes('social') || text.includes('instagram') || text.includes('tiktok') || text.includes('linkedin') || text.includes('facebook')) return 'social_media_prompt';
  if (
    text.includes('اعلان') ||
    text.includes('إعلان') ||
    text.includes('advertising') ||
    text.includes('ad ') ||
    text.includes('product') ||
    text.includes('منتج') ||
    text.includes('عربية') ||
    text.includes('سيارة') ||
    text.includes('مرسيدس') ||
    text.includes('mercedes')
  ) {
    return 'product_ad_prompt';
  }
  if (text.includes('full creative') || text.includes('art direction') || text.includes('visual system')) return 'full_creative_direction';
  if (text.includes('reference analysis') || text.includes('analyze reference')) return 'reference_analysis';

  const clearlyVisual = [
    'image', 'visual', 'prompt', 'design', 'poster', 'photo', 'صورة', 'فيجوال', 'تصميم', 'برومبت'
  ].some(term => text.includes(term));

  if (v === 'other' && clearlyVisual) return 'image_prompt';
  if (!v && clearlyVisual) return 'image_prompt';

  const fallback = 'image_prompt';
  return allowed.has(fallback) ? fallback : 'image_prompt';
}

const raw = $json || {};

const intake = pick(
  raw.intake,
  raw.wf00_intake,
  raw.input?.intake,
  {}
) || {};

const normalizer = pick(
  raw.normalizer_result,
  raw.normalizerResult,
  raw.sw00a_result,
  raw.sw00aResult,
  raw.input?.normalizer_result,
  {}
) || {};

const router = pick(
  raw.router_result,
  raw.routerResult,
  raw.sw00b_result,
  raw.sw00bResult,
  raw.input?.router_result,
  {}
) || {};

const brief = pick(
  raw.brief_decision_result,
  raw.briefDecisionResult,
  raw.sw00c_result,
  raw.sw00cResult,
  raw.input?.brief_decision_result,
  {}
) || {};

const workspace_id = uuidOrNull(pick(intake.workspace_id, raw.workspace_id));
const user_id = uuidOrNull(pick(intake.user_id, raw.user_id));
const project_id = uuidOrNull(pick(intake.project_id, raw.project_id));
const conversation_session_id = uuidOrNull(pick(raw.conversation_session_id, intake.conversation_session_id));
const source_user_message_id = uuidOrNull(pick(raw.user_message_id, intake.conversation_message_id, raw.source_user_message_id));
const assistant_message_id = uuidOrNull(pick(raw.assistant_message_id, intake.assistant_message_id));

const raw_input = String(pick(normalizer.raw_input, intake.message_text, raw.message_text, '') || '');
const normalized_english_input = String(pick(normalizer.normalized_english_input, '') || '');
const message_summary_english = String(pick(normalizer.message_summary_english, '') || '');
const brief_summary = String(brief.brief_summary || '');

const router_route = String(pick(router.route, '') || '');
const router_intent = String(pick(router.intent, '') || '');
const normalization_status = String(pick(normalizer.normalization_status, '') || '');

const can_create_prompt_request = toBool(pick(brief.can_create_prompt_request, false));
const missing_critical_fields = asArray(pick(brief.missing_critical_fields, []));
const meaningful_decisions = asArray(pick(brief.meaningful_decisions, []));

const output_type = canonicalOutputType(
  pick(brief.output_type, raw.output_type, null),
  raw_input,
  brief_summary
);

const platform = pick(brief.platform, raw.platform, null);

const errors = [];

if (String(raw.wf_status || '') !== 'ready') errors.push('wf00_status_not_ready');
if (raw.should_continue_pipeline !== true) errors.push('pipeline_not_marked_to_continue');
if (!workspace_id) errors.push('missing_or_invalid_workspace_id');
if (!user_id) errors.push('missing_or_invalid_user_id');
if (!raw_input.trim()) errors.push('missing_raw_input');

// Allow fallback if we still have usable text.
// Do not allow failed normalization unless raw input is usable and router/brief are valid.
const normalizationUsable =
  normalization_status === 'success' ||
  normalization_status === 'fallback' ||
  Boolean(raw_input.trim());

if (!normalizationUsable) errors.push('normalization_not_usable');

if (router_route !== 'create_prompt_request') errors.push('route_not_create_prompt_request');
if (router.needs_prompt_request !== true) errors.push('router_does_not_need_prompt_request');
if (can_create_prompt_request !== true) errors.push('brief_decision_cannot_create_prompt_request');
if (missing_critical_fields.length > 0) errors.push('missing_critical_fields_present');

const valid_handoff = errors.length === 0;

return [{
  json: {
    wf00: raw,
    intake,
    normalizer_result: normalizer,
    router_result: router,
    brief_decision_result: brief,

    workspace_id,
    user_id,
    project_id,
    conversation_session_id,
    source_user_message_id,
    assistant_message_id,

    raw_input,
    normalized_english_input,
    message_summary_english,

    output_type,
    platform,
    brief_summary,
    meaningful_decisions,
    missing_critical_fields,

    valid_handoff,
    errors
  }
}];

function clampConfidence(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 0.7;
  return Math.max(0, Math.min(1, n));
}

function toSnakeKey(value, fallback) {
  const cleaned = String(value || '')
    .trim()
    .replace(/([a-z0-9])([A-Z])/g, '$1_$2')
    .replace(/[^a-zA-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .toLowerCase();
  return cleaned || fallback;
}

function normalizeDecisionValue(value) {
  if (value === undefined || value === null) return {};
  if (Array.isArray(value)) return { values: value };
  if (typeof value === 'object') return { ...value };
  return { value };
}

function textFromDecisionValue(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (Array.isArray(value)) return value.map(textFromDecisionValue).filter(Boolean).join(' ');
  if (typeof value === 'object') {
    const priority = [
      value.value,
      value.subject,
      value.description,
      value.text,
      value.label,
      value.surface,
      value.environment,
      value.material,
      value.lighting,
      value.composition,
      value.camera,
      value.style,
      value.mood
    ].map(textFromDecisionValue).filter(Boolean);
    if (priority.length) return priority.join(' ');
    try { return JSON.stringify(value); } catch (e) { return ''; }
  }
  return '';
}

function includesAny(text, terms) {
  return terms.some(term => text.includes(term));
}

function inferSemanticDecisionKey(originalKey, decisionValue, usedKeys) {
  const text = textFromDecisionValue(decisionValue).toLowerCase();

  if (includesAny(text, ['lighting', 'light ', 'macro lighting', 'dramatic light', 'softbox', 'shadow', 'rim light', 'glow', 'illumination'])) {
    return 'lighting_direction';
  }

  if (includesAny(text, ['camera', 'lens', 'macro', 'close-up', 'close up', 'depth of field', 'dof', 'focal', 'angle', 'shot'])) {
    return 'camera_direction';
  }

  if (includesAny(text, ['composition', 'layout', 'framing', 'editorial composition', 'negative space', 'centered', 'rule of thirds'])) {
    return 'composition_direction';
  }

  if (includesAny(text, ['surface', 'background', 'backdrop', 'environment', 'setting', 'studio', 'table', 'floor', 'velvet', 'marble', 'wood', 'fabric', 'set '])) {
    return 'surface_environment';
  }

  if (includesAny(text, ['material', 'reflection', 'reflections', 'reflective', 'gloss', 'metal', 'gold', 'glass', 'velvet', 'texture', 'finish', 'polished'])) {
    return originalKey === 'creative_subject' && !usedKeys.has('creative_subject')
      ? 'creative_subject'
      : 'material_finish';
  }

  if (includesAny(text, ['color', 'palette', 'green', 'gold', 'blue', 'red', 'orange', 'monochrome', 'grade'])) {
    return 'color_palette';
  }

  if (includesAny(text, ['mood', 'style', 'premium', 'luxury', 'cinematic', 'editorial', 'minimal', 'dramatic'])) {
    return originalKey === 'visual_style' && !usedKeys.has('visual_style')
      ? 'visual_style'
      : 'requested_mood';
  }

  if (originalKey === 'creative_subject' && usedKeys.has('creative_subject')) return 'supporting_subject';
  if (originalKey === 'visual_style' && usedKeys.has('visual_style')) return 'visual_style_detail';
  if (originalKey === 'constraints' && usedKeys.has('constraints')) return 'constraints_detail';

  return originalKey;
}

function makeUniqueKey(preferredKey, usedKeys) {
  let key = preferredKey;
  let suffix = 2;
  while (usedKeys.has(key)) {
    key = preferredKey + '_' + suffix;
    suffix += 1;
  }
  return key;
}

function decisionFingerprint(key, value) {
  let valueText = '';
  try { valueText = JSON.stringify(value); } catch (e) { valueText = textFromDecisionValue(value); }
  return (key + ':' + valueText).toLowerCase();
}

function normalizeMeaningfulDecisions(decisions) {
  const input = Array.isArray(decisions) ? decisions : [];
  const usedKeys = new Set();
  const seenFingerprints = new Set();
  const normalized = [];

  for (const rawDecision of input) {
    if (!rawDecision || typeof rawDecision !== 'object') continue;

    const originalKey = toSnakeKey(rawDecision.decision_key, 'decision_' + (normalized.length + 1));
    const rawValue = rawDecision.decision_value ?? {};
    const decisionValue = normalizeDecisionValue(rawValue);
    const originalFingerprint = decisionFingerprint(originalKey, decisionValue);

    if (seenFingerprints.has(originalFingerprint)) continue;
    seenFingerprints.add(originalFingerprint);

    const semanticKey = usedKeys.has(originalKey)
      ? inferSemanticDecisionKey(originalKey, decisionValue, usedKeys)
      : originalKey;
    const decisionKey = makeUniqueKey(toSnakeKey(semanticKey, originalKey), usedKeys);
    usedKeys.add(decisionKey);

    if (decisionKey !== originalKey) {
      decisionValue.normalized_from_key = originalKey;
      decisionValue.normalization_reason = 'duplicate_decision_key_reclassified';
    }

    normalized.push({
      decision_key: decisionKey,
      decision_value: decisionValue,
      source: rawDecision.source ?? 'inferred',
      confidence_score: clampConfidence(rawDecision.confidence_score)
    });
  }

  return normalized.slice(0, 30);
}

const meaningful_decisions = normalizeMeaningfulDecisions($json.meaningful_decisions || []);

const normalizedBrief = {
  normalized_english_input: $json.normalized_english_input,
  message_summary_english: $json.message_summary_english,
  brief_summary: $json.brief_summary,
  meaningful_decisions,
  router_result: $json.router_result || {},
  attachments_summary: $json.intake?.attachments_summary || {},
  links: Array.isArray($json.intake?.links) ? $json.intake.links : [],
  source_conversation_session_id: $json.conversation_session_id || null,
  source_user_message_id: $json.source_user_message_id || null
};

const payload = {
  user_id: $json.user_id,
  workspace_id: $json.workspace_id,
  project_id: $json.project_id,
  raw_input: $json.raw_input,
  normalized_brief: normalizedBrief,
  detected_language: $json.normalizer_result?.detected_language || null,
  output_type: $json.output_type || null,
  platform: $json.platform || null,
  status: 'ready_for_generation',
  missing_fields: $json.missing_critical_fields || [],
  clarification_needed: false
};

return [{ json: { ...$json, meaningful_decisions, prompt_request_payload: payload } }];

