function mapDecisionSource(source) {
  const s = String(source || '').trim();

  if (s === 'user_explicit') return 'user';
  if (s === 'user') return 'user';

  if (s === 'inferred') return 'agent';
  if (s === 'agent') return 'agent';

  if (s === 'default' || s === 'system_default') return 'default';

  if (s === 'reference_analysis') return 'reference_analysis';
  if (s === 'brand_profile') return 'brand_profile';
  if (s === 'product_profile') return 'product_profile';
  if (s === 'character_profile') return 'character_profile';
  if (s === 'system') return 'system';

  return 'agent';
}

const base = $('Prepare Prompt Request Payload').first().json;
const created = $('Create Prompt Request').first().json || {};
const prompt_request_id = created.id || null;
const errors = Array.isArray(base.errors) ? [...base.errors] : [];

if (!prompt_request_id) {
  errors.push('prompt_request_create_failed');

  return [
    {
      json: {
        ...base,
        prompt_request_id: null,
        has_brief_decisions: false,
        brief_decisions_created: 0,
        errors
      }
    }
  ];
}

const decisions = normalizeMeaningfulDecisions(base.meaningful_decisions || []);

if (decisions.length === 0) {
  return [
    {
      json: {
        ...base,
        prompt_request_id,
        created_prompt_request: created,
        meaningful_decisions: decisions,
        has_brief_decisions: false,
        brief_decisions_created: 0,
        errors
      }
    }
  ];
}

return decisions.map((d, index) => ({
  json: {
    ...base,
    prompt_request_id,
    created_prompt_request: created,
    meaningful_decisions: decisions,
    has_brief_decisions: true,
    decision_index: index,
    decision_key: d.decision_key,
    decision_value: d.decision_value,
    source: mapDecisionSource(d.source),
    confidence_score: clampConfidence(d.confidence_score),
    errors
  }
}));

let base = {};
try { base = $('Prepare Brief Decisions').first().json || {}; } catch (e) { base = {}; }
const rows = $input.all().map(i => i.json || {});
const errors = Array.isArray(base.errors) ? [...base.errors] : [];
const failed = rows.filter(r => !r.id || r.error);
if (failed.length > 0) errors.push('brief_decisions_create_failed');
const count = rows.filter(r => r.id && !r.error).length;
return [{ json: { ...base, brief_decisions_created: count, created_brief_decisions: rows.filter(r => r.id && !r.error), errors } }];

