  if (v === undefined || v === null) return false;
  const s = String(v).trim();
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{12}$/i.test(s);
}
const prompt_request_id = $json.prompt_request_id || null;
const conversation_session_id = $json.conversation_session_id || null;
return [{ json: { ...$json, can_update_conversation_session: isUuid(prompt_request_id) && isUuid(conversation_session_id) } }];

function safeFirst(name) {
  try { return $(name).first().json || {}; } catch (e) { return {}; }
}

const current = $json || {};
const validated = safeFirst('Validate WF-00 Handoff');
const prepared = safeFirst('Prepare Prompt Request Payload');
const created = safeFirst('Create Prompt Request');

const decisionContext =
  Object.keys(safeFirst('Brief Decisions Created Context')).length
    ? safeFirst('Brief Decisions Created Context')
    : safeFirst('Skip Brief Decisions');

const prompt_request_id =
  created.id || current.prompt_request_id || decisionContext.prompt_request_id || null;

let errors = [];
for (const source of [validated.errors, prepared.errors, current.errors, decisionContext.errors]) {
  if (Array.isArray(source)) errors.push(...source.filter(Boolean));
}

if (validated.valid_handoff === false && errors.length === 0) {
  errors.push('invalid_wf00_handoff');
}

if (validated.valid_handoff === true && !prompt_request_id) {
  errors.push('prompt_request_create_failed');
}

errors = [...new Set(errors)];

const createdOk =
  Boolean(prompt_request_id) &&
  errors.filter(e => e !== 'conversation_session_update_failed').length === 0;

const output = {
  wf01_status: createdOk ? 'created' : 'failed',
  prompt_request_id: createdOk ? prompt_request_id : null,
  workspace_id: validated.workspace_id || null,
  user_id: validated.user_id || null,
  project_id: validated.project_id || null,
  conversation_session_id: validated.conversation_session_id || null,
  source_user_message_id: validated.source_user_message_id || null,
  output_type: validated.output_type || null,
  platform: validated.platform || null,
  prompt_request_status: 'ready_for_generation',
  brief_decisions_created: createdOk ? Number(decisionContext.brief_decisions_created || 0) : 0,
  next_workflow: createdOk ? 'WF-10 Prompt Generation Engine' : null,
  handoff_payload: {
    prompt_request_id: createdOk ? prompt_request_id : null,
    workspace_id: validated.workspace_id || null,
    user_id: validated.user_id || null,
    project_id: validated.project_id || null,
    output_type: validated.output_type || null,
    platform: validated.platform || null
  },
  errors
};

return [{ json: output }];

const created = $('Create Prompt Request').first().json || {};
const prepared = $('Prepare Prompt Request Payload').first().json || {};

return [{
  json: {
    created_id: created.id || null,
    created_error: created.error || null,
    created_raw: created,
    sent_payload: prepared.prompt_request_payload || null
  }
}];
